'use strict';

/* both sources, byte-exact, base64 (UTF-8). Left = SNEEKIE.BAS, right = docs/js/index.js. */
const BAS = new TextDecoder().decode(Uint8Array.from(atob(""), c => c.charCodeAt(0))).replace(/\n$/,'').split('\n');
const JS  = new TextDecoder().decode(Uint8Array.from(atob(""),  c => c.charCodeAt(0))).replace(/\n$/,'').split('\n');

/* ---------- GW-BASIC tokenizer ---------- */
const BKW = new Set(('REM DEFINT SCREEN WIDTH CLS RANDOMIZE DEF SEG POKE DIM LOCATE PRINT USING FOR TO STEP ' +
  'NEXT IF THEN ELSE GOTO GOSUB RETURN ON WHILE WEND SOUND PLAY END DATA READ RESTORE STRING$ SPC').split(' '));
const BFN = new Set('CHR$ INKEY$ INPUT$ ASC LEN MID$ INSTR INT RND PEEK TIMER VAL'.split(' '));
const BOP = new Set('AND OR NOT MOD'.split(' '));
const aZ = c => (c>='A'&&c<='Z')||(c>='a'&&c<='z'); const aN = c => aZ(c)||(c>='0'&&c<='9');
const dg = c => c>='0'&&c<='9'; const hx = c => dg(c)||(c>='A'&&c<='F')||(c>='a'&&c<='f');
function scanBas(s, out){
  let i=0; const n=s.length;
  while(i<n){ const c=s[i];
    if(c===' '||c==='\t'){ let j=i; while(j<n&&(s[j]===' '||s[j]==='\t'))j++; out.push(['ws',s.slice(i,j)]); i=j; continue; }
    if(c==="'"){ out.push(['com',s.slice(i)]); break; }
    if(c==='"'){ let j=i+1; while(j<n&&s[j]!=='"')j++; if(j<n)j++; out.push(['str',s.slice(i,j)]); i=j; continue; }
    if(c==='&'&&(s[i+1]==='H'||s[i+1]==='h')){ let j=i+2; while(j<n&&hx(s[j]))j++; out.push(['num',s.slice(i,j)]); i=j; continue; }
    if(dg(c)||(c==='.'&&dg(s[i+1]||''))){ let j=i; while(j<n&&(dg(s[j])||s[j]==='.'))j++; out.push(['num',s.slice(i,j)]); i=j; continue; }
    if(aZ(c)){ let j=i; while(j<n&&aN(s[j]))j++; if(s[j]==='$')j++; const w=s.slice(i,j), up=w.toUpperCase();
      if(up==='REM'){ out.push(['kw',w]); out.push(['com',s.slice(j)]); break; }
      out.push([BKW.has(up)?'kw':BFN.has(up)?'fn':BOP.has(up)?'op':'id', w]); i=j; continue; }
    if('=+-*/\\^<>'.includes(c)){ const two=s.substr(i,2); if(['<=','>=','<>','><'].includes(two)){ out.push(['op',two]); i+=2; continue; } out.push(['op',c]); i++; continue; }
    out.push(['pn',c]); i++;
  }
}
function tokBas(line){ const out=[]; const m=/^(\s*)(\d+)(?=\D|$)/.exec(line); if(m){ if(m[1])out.push(['ws',m[1]]); out.push(['ln',m[2]]); scanBas(line.slice(m[0].length),out); } else scanBas(line,out); return out; }

/* ---------- small JS tokenizer (carries block-comment state across lines) ---------- */
const JKW = new Set(('const let var function async await return if else for while do break continue switch case ' +
  'default new throw try catch finally typeof instanceof in of this true false null undefined void delete class ' +
  'extends super yield').split(' '));
function tokJs(lines){
  const rows=[]; let inBlock=false;
  for(const s of lines){ const out=[]; let i=0; const n=s.length;
    while(i<n){
      if(inBlock){ const e=s.indexOf('*/',i); if(e<0){ out.push(['com',s.slice(i)]); i=n; } else { out.push(['com',s.slice(i,e+2)]); i=e+2; inBlock=false; } continue; }
      const c=s[i];
      if(c===' '||c==='\t'){ let j=i; while(j<n&&(s[j]===' '||s[j]==='\t'))j++; out.push(['ws',s.slice(i,j)]); i=j; continue; }
      if(c==='/'&&s[i+1]==='/'){ out.push(['com',s.slice(i)]); i=n; continue; }
      if(c==='/'&&s[i+1]==='*'){ const e=s.indexOf('*/',i+2); if(e<0){ out.push(['com',s.slice(i)]); i=n; inBlock=true; } else { out.push(['com',s.slice(i,e+2)]); i=e+2; } continue; }
      if(c==='"'||c==="'"||c==='`'){ let j=i+1; while(j<n){ if(s[j]==='\\'){ j+=2; continue; } if(s[j]===c){ j++; break; } j++; } out.push(['str',s.slice(i,j)]); i=j; continue; }
      if(dg(c)||(c==='.'&&dg(s[i+1]||''))){ let j=i; if(c==='0'&&(s[i+1]==='x'||s[i+1]==='X')){ j=i+2; while(j<n&&hx(s[j]))j++; } else { while(j<n&&(dg(s[j])||s[j]==='.'))j++; } out.push(['num',s.slice(i,j)]); i=j; continue; }
      if(aZ(c)||c==='_'||c==='$'){ let j=i; while(j<n&&(aN(s[j])||s[j]==='_'||s[j]==='$'))j++; const w=s.slice(i,j);
        let k=j; while(k<n&&s[k]===' ')k++;
        out.push([JKW.has(w)?'kw':(s[k]==='(')?'fn':'id', w]); i=j; continue; }
      if('=+-*/%<>!&|?~^'.includes(c)){ out.push(['op',c]); i++; continue; }
      out.push(['pn',c]); i++;
    }
    rows.push(out);
  }
  return rows;
}

/* ---------- the pairings: title, prose, and line ranges into each source ---------- */
const SECTIONS = [
  { t:'The screen is the data model', bas:[[16,18]], js:[[51,54],[111,117]],
    h:`The 1988 code points <code>PEEK</code>/<code>POKE</code> at video memory and even chooses mono (<code>&amp;HB000</code>) vs colour (<code>&amp;HB800</code>). The port needs only one in-memory grid, so that choice vanishes &mdash; <code>vram</code> is a 4000-byte array and <code>poke()</code>/<code>peek()</code> are four lines each.`},
  { t:'Drawing the fixed frame', bas:[[19,28]], js:[[953,967]],
    h:`<code>LOCATE r,c : PRINT CHR$(n)</code> becomes <code>locate(r,c); pc(n)</code>; <code>STRING$(78,&hellip;)</code> becomes <code>pcn(196,78)</code>; <code>SPC(78)</code> becomes <code>sp(78)</code>. The wording was translated to English, but every box-drawing code is untouched.`},
  { t:'The level loop &amp; the snake seed', bas:[[32,39]], js:[[843,855]],
    h:`<code>FOR LEVEL=1 TO 32</code> is a <code>for</code> loop; the snake is seeded into <code>T()</code> at the same offsets (2000 tail, 1840 head); <code>ON LEVEL GOSUB</code> becomes one indexed call into the <code>CFG</code> table.`},
  { t:'Reading a key: blocking INKEY$ becomes async', bas:[[50,54]], js:[[180,188]],
    h:`<em>The biggest structural change.</em> The <code>INKEY$</code> wait loop (up to <code>Z</code> seconds) can't block a browser, so it becomes a Promise: <code>keyOrTimeout(ms)</code> resolves when a key is buffered <em>or</em> the timer fires. The game loop <code>await</code>s it &mdash; which is why the whole loop is <code>async</code>.`},
  { t:'Sorting the keypress, and ESC', bas:[[57,59]], js:[[879,886]],
    h:`<code>LEN(A$)</code> distinguishes a 2-character arrow key from a single keypress; the JS checks <code>A$.length</code>. <code>ASC(A$)=27</code> (ESC) becomes <code>charCodeAt(0) === 27</code> &mdash; which <code>throw</code>s the death signal instead of <code>GOTO 510</code>.`},
  { t:'Turning the head into a screen step', bas:[[72,78]], js:[[887,892]],
    h:`Identical arithmetic on offsets: a heading becomes a step of &plusmn;160 (one row) or &plusmn;2 (one column). <code>A</code> is the cell the head wants; <code>PEEK(A)</code> &rarr; <code>peek(A)</code> reveals what's there.`},
  { t:'What is in the next cell?', bas:[[79,98]], js:[[892,915]],
    h:`The <code>IF D&lt;&gt;n THEN GOTO</code> ladder becomes an <code>if / else if</code> chain on the same character codes &mdash; empty, club, heart, stone, smiley, arrow &mdash; with the same scoring, spawning and growth.`},
  { t:'Blocked by a wall or your own tail', bas:[[99,99]], js:[[916,918]],
    h:`Anything else means you can't move there. BASIC falls through to line 910; the JS sets <code>blocked = true</code>. Both restore the old heading, dock a little bonus, buzz, and skip the move &mdash; no death.`},
  { t:'Drawing the body bend', bas:[[100,106]], js:[[919,926]],
    h:`Six cases choose the box-drawing piece for the corner from the new heading <code>E</code> and the old one <code>F</code>, then append a fresh <span class="mono">&#9608;</span> head &mdash; carried across condition-for-condition.`},
  { t:'Shimmer &amp; the per-level hazard', bas:[[108,109]], js:[[928,931]],
    h:`The brightness "shimmer" loop and the <code>ON LEVEL GOSUB</code> that animates this level's arrows/gates become a <code>for</code> loop and one indexed call into the <code>ENEMY</code> table.`},
  { t:'Death: GOTO/RETURN 510 becomes a thrown signal', bas:[[59,71]], js:[[829,841],[932,936]],
    h:`BASIC dies by <code>GOTO 510</code> from the move code, and the hazard routines use <code>RETURN 510</code> to bail straight out of a <code>GOSUB</code>. JavaScript has neither, so death is <code>throw DEATH</code> caught around the loop &mdash; the same "jump out from anywhere", done with exceptions. (The catch sits in the move loop.)`},
  { t:'Two dispatch tables (ON LEVEL GOSUB)', bas:[[39,39],[240,256]], js:[[805,826]],
    h:`<code>ON LEVEL GOSUB</code> is a jump table; the port makes it literal. <code>CFG[]</code> holds each level's recipe (speed, item count, bonus step + which maze) and <code>ENEMY[]</code> holds the hazard to animate &mdash; both indexed by <code>(LEVEL-1) % 16</code>, so levels 17&ndash;32 reuse 1&ndash;16.`},
  { t:'Dropping an item on a random cell', bas:[[123,125]], js:[[612,618]],
    h:`<code>RND</code> &rarr; <code>Math.random()</code>. The even-offset trick (land on a character byte, not its colour byte) and the "is it empty?" test are unchanged.`},
  { t:'Scoring', bas:[[127,129]], js:[[620,629]],
    h:`Add <code>OP</code> to the score and bump the high score. <code>PRINT USING "######"</code> (a fixed-width number) becomes the helper <code>pu(6, &hellip;)</code>.`},
  { t:'Sound: SOUND f,d becomes a Web Audio note', bas:[[234,234]], js:[[267,296]],
    h:`<code>SOUND freq, ticks</code> (ticks of the 1/18.2&nbsp;s timer) becomes a short square-wave note scheduled on the Web Audio clock &mdash; same frequencies, same durations, queued so rapid blips don't overlap. <code>PLAY "mb"</code> just meant "don't pause".`},
  { t:'Input: INKEY$ scancodes become keydown', bas:[[72,72]], js:[[190,215]],
    h:`DOS returned an arrow from <code>INKEY$</code> as two bytes &mdash; <code>CHR$(0)</code> then a scancode &mdash; which line 640 takes apart with <code>ASC(MID$(A$,2,1))</code>. The browser's <code>keydown</code> handler manufactures those very same 2-byte strings (<code>'\\0H'</code> = up, &hellip;), so the loop sees exactly what it saw in 1988.`},
];

/* ---------- render ---------- */
const pairs = document.getElementById('pairs');
const tocList = document.getElementById('toc-list');

function lineDiv(toks){
  const d = document.createElement('div'); d.className = 'cl';
  for(const [cls, txt] of toks){
    if(cls === 'ws') d.appendChild(document.createTextNode(txt));
    else { const s = document.createElement('span'); s.className = 't-' + cls; s.textContent = txt; d.appendChild(s); }
  }
  if(!d.childNodes.length) d.appendChild(document.createTextNode('​'));
  return d;
}
function fillBas(host, ranges){
  ranges.forEach((r, ri) => {
    if(ri) host.appendChild(gap());
    for(const ln of BAS.slice(r[0]-1, r[1])) host.appendChild(lineDiv(tokBas(ln)));
  });
}
function fillJs(host, ranges){
  ranges.forEach((r, ri) => {
    if(ri) host.appendChild(gap());
    tokJs(JS.slice(r[0]-1, r[1])).forEach(toks => host.appendChild(lineDiv(toks)));
  });
}
function gap(){ const g = document.createElement('div'); g.className = 'gap'; g.textContent = '⋯'; return g; }

SECTIONS.forEach((sec, idx) => {
  const num = idx + 1;
  const s = document.createElement('section'); s.className = 'pairsec'; s.id = 'p-' + num;
  s.innerHTML =
    '<div class="phead"><span class="badge">' + num + '</span><h2>' + sec.t + '</h2></div>' +
    '<div class="prose">' + sec.h + '</div>' +
    '<div class="pair">' +
      '<div class="col"><div class="tag bas">1988 &middot; GW-BASIC</div><div class="code" data-b></div></div>' +
      '<div class="col"><div class="tag js">2026 &middot; JavaScript</div><div class="code" data-j></div></div>' +
    '</div>';
  pairs.appendChild(s);
  fillBas(s.querySelector('[data-b]'), sec.bas);
  fillJs(s.querySelector('[data-j]'), sec.js);

  const li = document.createElement('li');
  li.innerHTML = '<span class="n">' + num + '</span><a href="#p-' + num + '">' + sec.t + '</a>';
  tocList.appendChild(li);
});
